/**
 * An object describing the parameter values for the
 * [RouteParameters.attributeParameterValues](https://developers.arcgis.com/javascript/latest/references/core/rest/support/RouteParameters/#attributeParameterValues) property, which is used by
 * [RouteParameters](https://developers.arcgis.com/javascript/latest/references/core/rest/support/RouteParameters/), [ClosestFacilityParameters](https://developers.arcgis.com/javascript/latest/references/core/rest/support/ClosestFacilityParameters/) and [ServiceAreaParameters](https://developers.arcgis.com/javascript/latest/references/core/rest/support/ServiceAreaParameters/).
 *
 * @since 5.0
 */
export interface AttributeParameterValue {
  /**
   * The name of the attribute.
   *
   * @since 5.0
   */
  attributeName: string;
  /**
   * The name of the parameter associated with the restriction. A restriction can have one or more `parameterName` properties.
   *
   * @since 5.0
   */
  parameterName: string;
  /**
   * The value for `parameterName`.
   *
   * @since 5.0
   */
  value: string | number | null;
}

